import fs from 'node:fs';
import path from 'node:path';
import { fileURLToPath } from 'node:url';
import Papa from 'papaparse';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

const INPUT_PATH = path.resolve(__dirname, '../input-data/Glucose_Model_HRA_Mapping_v4.csv');
const OUTPUT_PATH = path.resolve(__dirname, '../docs/metadata.md');

// Prefix the output with a clear notice so the generated file is not edited manually.
const GENERATED_NOTICE = [
  '<!-- This file is generated by src/gen-biomodels-markdown.js. Do not edit by hand. -->',
  '<!-- Regenerate with: npm run generate:metadata -->',
].join('\n');

/**
 * Convert CSV header names into markdown-friendly labels.
 * @param {string} label
 * @returns {string}
 */
function formatLabel(label) {
  return label.replace(/_/g, ' ');
}

/**
 * Normalize empty CSV values to a consistent placeholder.
 * @param {unknown} value
 * @returns {string}
 */
function formatValue(value) {
  if (value === undefined || value === null || value === '') {
    return 'N/A';
  }

  return String(value).trim();
}

/**
 * Build the section heading for a model row.
 * @param {Record<string, string>} row
 * @param {number} index
 * @returns {string}
 */
function buildHeading(row, index) {
  const modelName = formatValue(row.Model_Name);
  const modelId = formatValue(row.Model_ID);

  if (modelName !== 'N/A' && modelId !== 'N/A') {
    return `## ${modelName} (${modelId})`;
  }

  if (modelName !== 'N/A') {
    return `## ${modelName}`;
  }

  if (modelId !== 'N/A') {
    return `## ${modelId}`;
  }

  return `## Row ${index + 1}`;
}

/**
 * Emit a stable HTML anchor so models can be referenced by Model_ID.
 * @param {Record<string, string>} row
 * @returns {string}
 */
function buildAnchor(row) {
  const modelId = formatValue(row.Model_ID);

  if (modelId === 'N/A') {
    return '';
  }

  return `<a id="${modelId}"></a>`;
}

/**
 * Render parsed CSV rows into the final markdown document.
 * @param {Array<Record<string, string>>} rows
 * @param {string[]} headers
 * @returns {string}
 */
function buildMarkdown(rows, headers) {
  const sections = rows
    .map((row, index) => {
      const anchor = buildAnchor(row);
      const heading = buildHeading(row, index);
      // Preserve CSV column order so the markdown stays aligned with the source file.
      const fields = headers.map((header) => `- **${formatLabel(header)}:** ${formatValue(row[header])}`).join('\n');

      return [anchor, heading, '', fields].filter(Boolean).join('\n');
    })
    .join('\n\n');

  return `${GENERATED_NOTICE}\n\n${sections}`;
}

/**
 * Parse the CSV text into row objects keyed by header name.
 * @param {string} csvText
 * @returns {Papa.ParseResult<Record<string, string>>}
 */
function parseCsv(csvText) {
  const result = Papa.parse(csvText, {
    header: true,
    skipEmptyLines: true,
  });

  if (result.errors.length > 0) {
    throw new Error(result.errors.map((error) => error.message).join('\n'));
  }

  if (!result.meta.fields || result.meta.fields.length === 0) {
    throw new Error('CSV did not contain any header fields.');
  }

  return result;
}

/**
 * Read the source CSV and write the generated markdown output.
 * @returns {void}
 */
function main() {
  const csv = fs.readFileSync(INPUT_PATH, 'utf8');
  const result = parseCsv(csv);

  const headers = result.meta.fields || [];
  const markdown = buildMarkdown(result.data, headers);

  fs.writeFileSync(OUTPUT_PATH, `${markdown}\n`, 'utf8');
}

main();
